INSERT INTO public.email_templates (template_key, name, subject, heading, body_text, button_text, footer_text, primary_color, logo_url, is_active)
VALUES
  ('partner_application_received', 'Värdansökan mottagen', 'Din ansökan har mottagits', 'Tack för din ansökan!', 'Hej {{first_name}},\n\nVi har mottagit din ansökan om att bli värd hos Studentresor. Vårt team granskar din ansökan och återkommer inom 24 timmar.\n\nUnder tiden kan du förbereda information om ditt boende som du vill lägga upp på plattformen.', 'Besök Studentresor', 'Detta mail skickades automatiskt från Studentresor.\nDu får detta mail eftersom du har ansökt om att bli värd.', '#0c4a6e', NULL, true),
  ('partner_application_approved', 'Värdansökan godkänd', 'Din ansökan har godkänts!', 'Välkommen som värd!', 'Hej {{first_name}},\n\nVi är glada att meddela att din ansökan om att bli värd hos Studentresor har godkänts!\n\nDu kan nu logga in på värdportalen och börja lägga upp dina boenden. Vi ser fram emot att samarbeta med dig.', 'Logga in på värdportalen', 'Detta mail skickades automatiskt från Studentresor.\nDu får detta mail eftersom du har godkänts som värd.', '#0c4a6e', NULL, true),
  ('partner_application_rejected', 'Värdansökan nekad', 'Angående din värdansökan', 'Tack för ditt intresse', 'Hej {{first_name}},\n\nTack för din ansökan om att bli värd hos Studentresor. Tyvärr kan vi inte godkänna din ansökan vid denna tidpunkt.\n\nOm du har frågor eller vill diskutera beslutet, vänligen kontakta oss på info@studentresor.com.', '', 'Detta mail skickades automatiskt från Studentresor.\nDu får detta mail eftersom du har ansökt om att bli värd.', '#0c4a6e', NULL, true)
